// Typed helpers for axios-style errors. Use instead of `catch (e: any)` to
// extract a status code, correlation id, and message safely.
import { ExtractCorrelationId } from './common';

export interface ApiErrorInfo {
  httpStatus: number;
  correlationId?: string;
  message?: string;
}

interface AxiosLikeError {
  response?: {
    status?: number;
    headers?: Record<string, string>;
    data?: { message?: string };
  };
  message?: string;
}

function asAxiosLike(err: unknown): AxiosLikeError {
  return (err && typeof err === 'object') ? (err as AxiosLikeError) : {};
}

export function getApiError(err: unknown): ApiErrorInfo {
  const e = asAxiosLike(err);
  return {
    httpStatus: e.response?.status ?? 0,
    correlationId: ExtractCorrelationId(err),
    message: e.response?.data?.message ?? e.message,
  };
}

export function getHttpStatus(err: unknown): number {
  return asAxiosLike(err).response?.status ?? 0;
}
